// Script Continued Below
var uiConditionCheck = Class.create();
uiConditionCheck.prototype = {
	initialize: function() {

	},

	// v2.6
	canAcceptAssignment: function(gr){
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var inAssigned = (gr.state == 1);

		var isActionAllowedForTaskType = (gr.tasker_type.getDisplayValue() != "Acknowledgement"  && gr.tasker_type.getDisplayValue() != "Information Only");

		var inStateAllowedCurrentUser = (isActionAllowedForTaskType && currentUserIsAssignedMember && inAssigned);


		if(canRead && isActive && inStateAllowedCurrentUser){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	canAcknowledgeTask: function(gr){
		// current.canRead() && current.state == 1 && (current.assigned_to == gs.getUserID()) &&current.tasker_type.getDisplayValue() == "Acknowledgement"
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var inAssigned = (gr.state == 1);

		var isActionAllowedForTaskType = gr.tasker_type.getDisplayValue() == "Acknowledgement";

		var inStateAllowedCurrentUser = (isActionAllowedForTaskType && currentUserIsAssignedMember && inAssigned);


		if(canRead && isActive && inStateAllowedCurrentUser){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canActivateTemplateTask: function(gr){
		// !current.active && new UserInfoScripts().userHasProcessRights(current) && !current.isNewRecord();
		var answer = false;
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasTemplateRights = new UserInfoScripts().userHasProcessRights(gr);

		if(canRead && !isActive && !isNewRecord && currentUserHasTemplateRights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canActivateTemplate: function(gr){
		// !current.u_active && new UserInfoScripts().userHasProcessRights(current) && !current.isNewRecord();
		var answer = false;
		var isActive = gr.u_active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasTemplateRights = new UserInfoScripts().userHasProcessRights(gr);

		if(canRead && !isActive && !isNewRecord && currentUserHasTemplateRights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canActivateOU: function(gr){
		// !current.isNewRecord() && !current.active && new MarkInactiveConditionalMethods().checkOrgHierarchyPermission(current.sys_id)
		var answer = false;
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasOURights = new MarkInactiveConditionalMethods().checkOrgHierarchyPermission(gr.sys_id);

		if(canRead && !isActive && !isNewRecord && currentUserHasOURights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canAssignTaskToSelf: function(gr){
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);

		var inUnassigned = (gr.state == -5);		
		var inAssignmentRejected = (gr.state == 11);

		var uis = new UserInfoScripts();

		var isUserInOu = uis.IsUserInOU(gr.primary_assignee, currentUser);
		var inStateAllowedCurrentUser = (isUserInOu && (inUnassigned || inAssignmentRejected));

		if(canRead && isActive && (inStateAllowedCurrentUser) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canAssignTask: function(gr){
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);

		var inUnassigned = (gr.state == -5);		
		var inAssignmentRejected = (gr.state == 11);

		var isUserTaskingAuthority = new UserInfoScripts().IsUserTaskingAuthority(gr.primary_assignee, currentUser);
		var inStateAllowedCurrentUser = (isUserTaskingAuthority && (inUnassigned || inAssignmentRejected));

		if(canRead && isActive && (inStateAllowedCurrentUser) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canCancelSuggestedTask: function(gr){
		// current.canRead() && (current.u_created_task.nil()) && current.active 
		var answer = false;
		var isActive = gr.active;
		var canRead = gr.canRead();
		var taskNotCreated = gr.u_created_task.nil();
		// NOTE: there was no user in this, but probably should check for admin or the user on the email

		if(canRead && isActive && taskNotCreated ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canCreateSuggestedTask: function(gr){
		// current.canCreate() && (current.u_created_task.nil()) && current.active 
		var answer = false;
		var isActive = gr.active;
		var canRead = gr.canRead();
		var canCreate = gr.canCreate();
		var taskNotCreated = gr.u_created_task.nil();
		// NOTE: there was no user in this, but probably should check for admin or the user on the email

		if(canRead && canCreate && isActive && taskNotCreated ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canDeactivateTemplateTask: function(gr){
		// current.active && new UserInfoScripts().userHasProcessRights(current) && !current.isNewRecord();
		var answer = false;
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasTemplateRights = new UserInfoScripts().userHasProcessRights(gr);

		if(canRead && isActive && !isNewRecord && currentUserHasTemplateRights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canDeactivateTemplate: function(gr){
		// current.u_active && new UserInfoScripts().userHasProcessRights(current)
		var answer = false;
		var isActive = gr.u_active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasTemplateRights = new UserInfoScripts().userHasProcessRights(gr);

		if(canRead && isActive && !isNewRecord && currentUserHasTemplateRights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canDeactivateOU: function(gr){
		// current.active == true && new MarkInactiveConditionalMethods().checkOrgHierarchyPermission(current.sys_id)
		var answer = false;
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var canRead = gr.canRead();
		var currentUserHasOURights = new MarkInactiveConditionalMethods().checkOrgHierarchyPermission(gr.sys_id);

		if(canRead && isActive && !isNewRecord && currentUserHasOURights){
			answer = true;
		}else{
			answer = false;
		}
		return answer;		
	},

	// v2.6 - STRY0093759
	canRejectAssignment: function(gr){
		// used to be this
		//current.canRead() && current.state == 1 && (current.assigned_to == gs.getUserID()) && (current.tasker_type.getDisplayValue() != "Acknowledgement"  && current.tasker_type.getDisplayValue() != "Information Only")
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();

		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);

		var isStateAllowedForTaskType = (gr.tasker_type.getDisplayValue() != "Acknowledgement"  && gr.tasker_type.getDisplayValue() != "Information Only");

		// Assigned {1}, Accepted {10}
		var	inAssigned = (gr.state == "1");

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && currentUserIsAssignedMember && inAssigned);

		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6 - STRY0093759
	canRejectTaskForPrimaryAssignee: function(gr){
		// used to be this
		// current.canRead()   &&  !current.primary_assignee.nil() && (current.state ==-5 ) && new UserInfoScripts().IsUserTaskingAuthority(current.primary_assignee, gs.getUserID())

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();

		var isPrimaryAssigneePopulated = !gr.primary_assignee.nil();
		var inUnassigned = (gr.state == "-5");
		var isUserTaskingAuthority = new UserInfoScripts().IsUserTaskingAuthority(gr.primary_assignee, currentUser);

		if(canRead && isActive && isPrimaryAssigneePopulated && inUnassigned && isUserTaskingAuthority){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6
	canActionReviewTask: function(gr, action){
		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);

		var isStateAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.tasker_type, action);
		var	inReview = (gr.state == 14);

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && currentUserIsAssignedMember && inReview);

		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.6 - STRY0093759
	canStartWork: function(gr){
		// used to be this
		//current.canRead() && current.state ==10 && (current.assigned_to == gs.getUserID())

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();

		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var isStateAllowedForTaskType = (gr.tasker_type.getDisplayValue() == "Standard");

		// Assigned {1}, Accepted {10}
		var	inAssigned = (gr.state == "1");
		var	inAccepted = (gr.state == "10");

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && currentUserIsAssignedMember && (inAssigned || inAccepted));

		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},	

	// v2.6
	canStartScheduledWork: function(gr){
		// used to be this
		// current.canRead() && current.state==12  && (current.assigned_to == gs.getUserID()) 

		var answer = false;
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var isActionAllowedForTaskType = (gr.tasker_type.getDisplayValue() != "Acknowledgement"  && gr.tasker_type.getDisplayValue() != "Information Only");

		// Scheduled Work {12}
		var	inScheduledWork = (gr.state == "12");
		var inStateAllowedAssignedMember = (isActionAllowedForTaskType && currentUserIsAssignedMember && inScheduledWork);

		if(canRead && isActive && !isNewRecord && inStateAllowedAssignedMember ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},	

	// v2.6 - STRY0093759
	canSetReworkInProgress: function(gr){
		// used to be this
		//current.canRead()  && current.state==15  && (current.assigned_to == gs.getUserID())

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);

		// Assigned {1}, Accepted {10}
		var	inRework = (gr.state == "15");

		var inStateAllowedAssignedMember = (currentUserIsAssignedMember && inRework);

		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},	

	// v2.5 P3 - STRY0082305
	canSendToRework: function(gr){
		// used to be this
//current.canRead() && current.state == 14 &&  ( current.u_task_requester == gs.getUserID() || current.u_reviewer == gs.getUserID() )  && new TaskerTypeActions().IsActionAllowed(current.tasker_type,'Send to Rework')

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();
		var isTaskeOwner = current.u_task_requester == gs.getUserID();
		var isReviewer = current.u_reviewer == gs.getUserID();

		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		//var isStateAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.tasker_type,'Send to Review');
		var isStateAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(current.tasker_type,'Send to Rework');
		var	inReview = (gr.state == "14");

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && (isReviewer || isTaskeOwner) && (inReview));

		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},	

// v2.5 P3 - STRY0085434 
	canSendToReview: function(gr){
		// used to be this
		//current.canRead() && current.state == 13  && (current.assigned_to == gs.getUserID())  && (current.tasker_type.getDisplayValue() != "Acknowledgement"  && current.tasker_type.getDisplayValue() != "Information Only")
		// && new TaskerTypeActions().IsActionAllowed(current.tasker_type,'Mark Complete')

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();

		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		//var isStateAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.tasker_type,'Send to Review');
		var isStateAllowedForTaskType = (gr.tasker_type.getDisplayValue() == "Standard");
		var	assigned = (gr.state == "1");
		var	accepted = (gr.state == "10");
		var	workInProgress = (gr.state == "13");
		var	inReview = (gr.state == "14");
		var	reWork = (gr.state == "15");

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && (currentUserIsAssignedMember) && (assigned || accepted || workInProgress || reWork));
		if(canRead && isActive && (inStateAllowedAssignedMember) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},	
	// v2.5 P3 - STRY0085434 
	canMarkComplete: function(gr){
		// used to be this
		//current.canRead()  && current.state == 14 &&  ( current.u_task_requester == gs.getUserID() || current.u_reviewer == gs.getUserID() )
		// && new TaskerTypeActions().IsActionAllowed(current.tasker_type,'Mark Complete')

		var answer = false;
		var isActive = gr.active;
		var currentUser = gs.getUserID();
		var canRead = gr.canRead();

		var currentUserIsTaskOwner = (gr.u_task_requester == currentUser);
		var currentUserIsReviewer = (gr.u_reviewer == currentUser);
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var isReviewRequired = (gr.provide_response + '' == 'true');
		var isStateAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.tasker_type,'Mark Complete');

		var	assigned = (gr.state == "1");
		var	accepted = (gr.state == "10");
		var	workInProgress = (gr.state == "13");
		var	inReview = (gr.state == "14");
		var	reWork = (gr.state == "15");

		var inStateAllowedAssignedMember = (isStateAllowedForTaskType && (currentUserIsAssignedMember && !isReviewRequired) && (assigned || accepted || workInProgress || inReview || reWork));

		var inStateAllowedReviewer = (isStateAllowedForTaskType && currentUserIsReviewer && inReview);
		var inStateAllowedTaskOwner = (isStateAllowedForTaskType && currentUserIsTaskOwner && inReview);

		if( canRead && isActive && (inStateAllowedAssignedMember || inStateAllowedReviewer || inStateAllowedTaskOwner) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.5.3
	canCreateTasksForAllMembersInOU: function(gr){
		var answer = false;
		var currentUser = gs.getUserID();
		var canCreate = gr.canCreate();
		var isNotNew = gr.sys_id != -1;
		var isActive = gr.active;
		var isNotRestricted = !gr.assignment_group;
		var ouIsAssigned = gr.getValue('primary_assignee')!='';
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var currentUserIsTaskOwner = (gr.u_task_requester == currentUser);
		var isGlobalTA_OR_OUTA = new UserInfoScripts().IsUserTaskingAuthority(gr.primary_assignee, currentUser);

		var unassigned = (gr.state == "-5");
		var	assigned = (gr.state == "1");
		var	accepted = (gr.state == "10");
		// STRY0082933 
		var	rejected = (gr.state == "11");
		var	workInProgress = (gr.state == "13");
		var	inReview = (gr.state == "14");
		var	reWork = (gr.state == "15");
		var inStateAllowed = (unassigned ||	assigned ||	rejected || accepted ||	workInProgress || inReview || reWork);


		if(canCreate && isNotNew && isActive && inStateAllowed && isNotRestricted && ouIsAssigned && isGlobalTA_OR_OUTA && (currentUserIsAssignedMember || currentUserIsTaskOwner) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},

	// v2.5.3
	canCreateTasksForAllSubOU: function(gr){
		var answer = false;
		var currentUser = gs.getUserID();
		var canCreate = gr.canCreate();
		var isNotNew = gr.sys_id != -1;
		var isActive = gr.active;
		var isNotRestricted = !gr.assignment_group;
		var ouIsAssigned = gr.getValue('primary_assignee')!='';
		var currentUserIsAssignedMember = (gr.assigned_to == currentUser);
		var currentUserIsTaskOwner = (gr.u_task_requester == currentUser);
		var isGlobalTA_OR_OUTA = new UserInfoScripts().IsUserTaskingAuthority(gr.primary_assignee, currentUser);
		var isOpenSystem = new tasking_System_Settings_Scripts().systemControlSetting.Open;

		if(canCreate && isNotNew && isActive && isNotRestricted && ouIsAssigned && (isGlobalTA_OR_OUTA || isOpenSystem) && (currentUserIsAssignedMember || currentUserIsTaskOwner) ){
			answer = true;
		}else{
			answer = false;
		}
		return answer;
	},


	//v2.5.10
	//-----------------------------------------------------------------------------------------------------------------
	//KT: REQUEST TYPE
	//-----------------------------------------------------------------------------------------------------------------
	SubmitTaskerRequest: function(current){

		//KT: current is from Request table: We don't have a way to restrict the UI Action on the client
		var canCreate = current.canCreate();

		if (canCreate) {
			return true;
		} else{
			return false;
		}
	},

	RequestReassignment: function(current){

		var currentUser = gs.getUserID();
		//KT: current is from Task table: uses current directly
		if (current.getTableName() == "x_153465_discovert_route_task_instance") {
			var canRead = current.canRead();
			var isActive = current.active;
			var state = current.state;
			var reassignment_requested = current.reassignment_requested;
			var assignedTo = current.assigned_to;

			if(canRead && isActive == true && state == 13 && reassignment_requested == false &&
				assignedTo == currentUser){
				return true;
			} else{
				return false;
			}
		}

		//KT: current is from Request table: We don't have a way to restrict the UI Action on the client
		if (current.getTableName() == "x_153465_discovert_tasker_requests") {
			return true;
		} else{
			return false;
		}
	},


	RespondReassignment: function(current){

		var canRead;
		var isActive;
		var state;
		var reassignment_requested;
		var isTaskingAuthority;

		//KT: current is from Task table: uses current directly
		if (current.getTableName() == "x_153465_discovert_route_task_instance") {
			canRead = current.canRead();
			isActive = current.active;
			state = current.state;
			reassignment_requested = current.reassignment_requested;
			isTaskingAuthority = new UserInfoScripts().IsUserTaskingAuthority(current.primary_assignee, gs.getUserID());
		}

		//KT: current is from Request table: uses current.parent -> Task
		if (current.getTableName() == "x_153465_discovert_tasker_requests") {
			canRead = current.parent.canRead();
			isActive = current.parent.active;
			state = current.parent.state;
			reassignment_requested = current.parent.reassignment_requested;
			isTaskingAuthority = new UserInfoScripts().IsUserTaskingAuthority(current.parent.primary_assignee, gs.getUserID());
		}

		if(canRead && isActive == true && state == 13 && reassignment_requested == true && isTaskingAuthority == true){
			return true;
		} else{
			return false;
		}
	},


	RequestExtension: function(current){
		var canRead = current.canRead();
		var newRecord = current.sys_id;
		var isActive = current.active;
		var extension_requested  = current.extension_requested;
		var currentUser = gs.getUserID();
		var isAssignedTo = currentUser == current.assigned_to;
		var isReviewer = currentUser == current.u_reviewer;
		var isTaskOwner = currentUser == current.u_task_requester;

		// STRY0088624 
		var isSuspenseDateSet = (current.getDisplayValue('suspense_date') != '');

		// STRY0104349 - set states and types
		var accepted = (current.state == "10");
		var workInProgress = (current.state == "13");
		var inReview = (current.state == "14");
		var reWork = (current.state == "15");
		var isStandardType = (current.tasker_type.getDisplayValue() == "Standard");
		var isReviewType = (current.tasker_type.work_type == "review_item");

		// set states for reviewer
		var reviewerCanRequest = (isStandardType && isReviewer && inReview) || (isReviewType && isReviewer && (accepted || inReview));
		// set states for assigned member
		var assignedMemberCanRequest = (isStandardType && isAssignedTo && (accepted || workInProgress || reWork || inReview));


		if(isSuspenseDateSet && canRead && (newRecord != -1) && isActive && !extension_requested && !isTaskOwner && 
			(reviewerCanRequest || assignedMemberCanRequest )) {			
			return true;
		} else{
			return false;
		}

	},

	RespondExtension: function(current){
		var canRead;
		var isActive;
		var state;
		var extension_requested;
		var taskOwner;
		var currentUser = gs.getUserID();
		var tasker_type;
		var work_type;
		//KT: current is from Task table: uses current directly
		if (current.getTableName() == "x_153465_discovert_route_task_instance") {
			canRead = current.canRead();
			isActive = current.active;
			state = current.state;
			extension_requested = current.extension_requested;
			taskOwner = current.u_task_requester;
			tasker_type = current.tasker_type.getDisplayValue();
			work_type = current.tasker_type.work_type;
		}
		//KT: current is from Request table: uses current.parent -> Task
		if (current.getTableName() == "x_153465_discovert_tasker_requests") {
			canRead = current.parent.canRead();
			isActive = current.parent.active;
			state = current.parent.state;
			extension_requested = current.parent.extension_requested;
			taskOwner = current.parent.u_task_requester;
			tasker_type = current.parent.tasker_type.getDisplayValue();
			work_type = current.parent.tasker_type.work_type;
		}
		// STRY0104533
		var isTaskOwner = currentUser == taskOwner;
		// STRY0104349 - set states and types
		var accepted = (state == "10");
		var workInProgress = (state == "13");
		var inReview = (state == "14");
		var reWork = (state == "15");
		var isStandardType = (tasker_type == "Standard");
		var isReviewType = (work_type == "review_item");
		// set states response is allowed
		var UserCanRespond = (isStandardType && (accepted || workInProgress || reWork || inReview)) || (isReviewType && (accepted || inReview));

		// see if User is a task manager for the Task owner
		var isTaskManagerOfTaskOwner = new UserInfoScripts().IsUserOUTAOfAnotherUser(taskOwner, currentUser);
		var isUserTaskAdministrator =  new UserInfoScripts().IsUserTaskAdministrator(currentUser);
		if(canRead && isActive == true && UserCanRespond && extension_requested == true && (isTaskOwner || isTaskManagerOfTaskOwner || isUserTaskAdministrator)){
			return true;
		} else{
			return false;
		}
	},


	RequestClarification: function(current){

		var currentUser = gs.getUserID();
		var clarificationRequested;
		var canRead;
		//if task is in any of the below states
		var unassigned;
		var assigned;
		var accepted;
		var workInProgress;
		var inReview;
		var reWork;
		//check the to see if the current logged in user has any of the following tasker roles
		var currentUserIsTaskOwner;
		var currentUserIsAssignedMember;
		var currentUserIsReviewer;


		//KT: gr is from Task table: uses gr directly
		if (current.getTableName() == "x_153465_discovert_route_task_instance") {

			clarificationRequested = current.u_clarification_requested;
			canRead = current.canRead();
			//if task is in any of the below states
			unassigned = (current.state == "-5");
			assigned = (current.state == "1");
			accepted = (current.state == "10");
			workInProgress = (current.state == "13");
			inReview = (current.state == "14");
			reWork = (current.state == "15");
			//check the to see if the current logged in user has any of the following tasker roles
			currentUserIsTaskOwner = (current.u_task_requester == currentUser);
			currentUserIsAssignedMember = (current.assigned_to == currentUser);
			currentUserIsReviewer = (current.u_reviewer == currentUser);

			//NOTE EXCEPTION: If the (Task Owner), (Assigned Member) and (Reviewer) are the same person on the task form he/she should not be able request clarification (current behavior STRY0024957)
			if ( clarificationRequested == false && currentUserIsTaskOwner == true && currentUserIsAssignedMember == true && currentUserIsReviewer == true) {
				return false;
			}
			else  {
				//KT - STRY0050724
				var arrayUtil = new global.ArrayUtil();
				var arrayPrimaryAssigneeOUTAs = [];
				var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
				var listOfPrimaryAssigneeOUTAs  =  current.primary_assignee.tasking_authorities;
				arrayPrimaryAssigneeOUTAs = listOfPrimaryAssigneeOUTAs.toString().split(",");
				var isPrimaryAssigneeOUTA = arrayUtil.contains(arrayPrimaryAssigneeOUTAs, currentUser); //new UserInfoScripts().sysIdInList(currentUser, listOfPrimaryAssigneeOUTAs);

				//As an Assigned Member OR Reviewer OR Primary Assignee Task Manager (OUTA) OR Task Administrator (GTA), I can click the "Request Clarification" UI Action on tasks that are in the following states, so that I am clear on the assignment.
				if ( canRead && clarificationRequested == false  &&
					(currentUserIsAssignedMember || currentUserIsReviewer || isPrimaryAssigneeOUTA || isGTA ) &&
					(unassigned || assigned || accepted || workInProgress || inReview || reWork )){
					return true;
				}else{
					return false;
				}
			}
		}
		//else return false;

		//KT: current is from Request table: uses current.parent -> Task
		if (current.getTableName() == "x_153465_discovert_tasker_requests") {

			clarificationRequested = current.parent.u_clarification_requested;
			canRead = current.parent.canRead();
			//if task is in any of the below states
			unassigned = (current.parent.state == "-5");
			assigned = (current.parent.state == "1");
			accepted = (current.parent.state == "10");
			workInProgress = (current.parent.state == "13");
			inReview = (current.parent.state == "14");
			reWork = (current.parent.state == "15");
			//check the to see if the current logged in user has any of the following tasker roles
			currentUserIsTaskOwner = (current.parent.u_task_requester == currentUser);
			currentUserIsAssignedMember = (current.parent.assigned_to == currentUser);
			currentUserIsReviewer = (current.parent.u_reviewer == currentUser);

			//NOTE EXCEPTION: If the (Task Owner), (Assigned Member) and (Reviewer) are the same person on the task form he/she should not be able request clarification (current behavior STRY0024957)
			if (canRead && clarificationRequested == false && currentUserIsTaskOwner == true && currentUserIsAssignedMember == true && currentUserIsReviewer == true) {
				return false;
			}
			else  {
				//KT - STRY0050724
				var arrayUtil = new global.ArrayUtil();
				var arrayPrimaryAssigneeOUTAs = [];
				var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
				var listOfPrimaryAssigneeOUTAs  =  current.primary_assignee.tasking_authorities;
				arrayPrimaryAssigneeOUTAs = listOfPrimaryAssigneeOUTAs.toString().split(",");
				var isPrimaryAssigneeOUTA = arrayUtil.contains(arrayPrimaryAssigneeOUTAs, currentUser); //new UserInfoScripts().sysIdInList(currentUser, listOfPrimaryAssigneeOUTAs);

				//As an Assigned Member OR Reviewer OR Primary Assignee Task Manager (OUTA) OR Task Administrator (GTA), I can click the "Request Clarification" UI Action on tasks that are in the following states, so that I am clear on the assignment.
				if ( canRead && clarificationRequested == false && 
					(currentUserIsAssignedMember || currentUserIsReviewer || isPrimaryAssigneeOUTA || isGTA ) &&
					(unassigned || assigned || accepted || workInProgress || inReview || reWork )){
					return true;
				}else{
					return false;
				}
			}
		}

	},


	RespondClarification: function(current){

		//KT - STRY0050725
		var arrayUtil = new global.ArrayUtil();

		var canRead;
		var currentUser =  gs.getUserID();
		var clarificationRequested;
		var isTopTask;
		//if task is in any of the below states
		var unassigned;
		var assigned;
		var accepted;
		var workInProgress;
		var inReview;
		var reWork;
		//check the to see if the current logged in user has any of the following tasker roles
		var taskOwner;
		var currentUserIsAssignedMember;

		var arrayPrimaryOfficeOUTAs = [];
		var listOfPrimaryOfficeOUTAs;
		var isPrimaryOfficeOUTA;

		var arrayPrimaryAssigneeOUTAs = [];
		var listOfPrimaryAssigneeOUTAs;
		var isPrimaryAssigneeOUTA;
		// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Administrators to the people who can respond
		var arrayTaskAdministrators = [];
		var listOfTaskAdministrators;
		var isTaskAdministrator;


		//KT: current is from Task table: uses current directly
		if (current.getTableName() == "x_153465_discovert_route_task_instance") {

			canRead = current.canRead();
			clarificationRequested = current.u_clarification_requested;
			isTopTask = current.parent.nil();
			//if task is in any of the below states
			unassigned = (current.state == "-5");
			assigned = (current.state == "1");
			accepted = (current.state == "10");
			workInProgress = (current.state == "13");
			inReview = (current.state == "14");
			reWork = (current.state == "15");
			//check the to see if the current logged in user has any of the following tasker roles
			taskOwner = (current.u_task_requester == currentUser);
			currentUserIsAssignedMember = (current.assigned_to == currentUser);

			// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Administrators to the people who can respond
			listOfTaskAdministrators = current.primary_office.u_global_authorities;
			arrayTaskAdministrators = listOfTaskAdministrators.toString().split(",");
			isTaskAdministrator = arrayUtil.contains(arrayTaskAdministrators, currentUser); 

			//Top Task
			if(isTopTask == true){
				//KT - STRY0050725: if this is not a subtask get the list of primary office outas and check that the current user is in the list
				listOfPrimaryOfficeOUTAs  =  current.primary_office.tasking_authorities;
				arrayPrimaryOfficeOUTAs = listOfPrimaryOfficeOUTAs.toString().split(",");
				isPrimaryOfficeOUTA = arrayUtil.contains(arrayPrimaryOfficeOUTAs, currentUser); 
			}
			//Sub Task
			if(isTopTask == false){
				//KT - STRY0050725: if this is a subtask get the list of primary assignee outas and check that the current user is in the list
				listOfPrimaryAssigneeOUTAs  =  current.parent.primary_assignee.tasking_authorities;
				arrayPrimaryAssigneeOUTAs = listOfPrimaryAssigneeOUTAs.toString().split(",");
				isPrimaryAssigneeOUTA = arrayUtil.contains(arrayPrimaryAssigneeOUTAs, currentUser); 
			}
		}

		//KT: current is from Request table: uses current.parent -> Task
		if (current.getTableName() == "x_153465_discovert_tasker_requests") {

			canRead = current.parent.canRead();
			clarificationRequested = current.parent.u_clarification_requested;
			isTopTask = current.parent.parent.nil();
			//if task is in any of the below states
			unassigned = (current.parent.state == "-5");
			assigned = (current.parent.state == "1");
			accepted = (current.parent.state == "10");
			workInProgress = (current.parent.state == "13");
			inReview = (current.parent.state == "14");
			reWork = (current.parent.state == "15");
			//check the to see if the current logged in user has any of the following tasker roles
			taskOwner = (current.parent.u_task_requester == currentUser);
			currentUserIsAssignedMember = (current.parent.assigned_to == currentUser);

			// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Administrators to the people who can respond
			listOfTaskAdministrators = current.parent.primary_office.u_global_authorities;
			arrayTaskAdministrators = listOfTaskAdministrators.toString().split(",");
			isTaskAdministrator = arrayUtil.contains(arrayTaskAdministrators, currentUser); 

			//Top Task
			if(isTopTask == true){
				//KT - STRY0050725: if this is not a subtask get the list of primary office outas and check that the current user is in the list
				listOfPrimaryOfficeOUTAs  =  current.parent.primary_office.tasking_authorities;
				arrayPrimaryOfficeOUTAs = listOfPrimaryOfficeOUTAs.toString().split(",");
				isPrimaryOfficeOUTA = arrayUtil.contains(arrayPrimaryOfficeOUTAs, currentUser); 
			}
			//Sub Task
			if(isTopTask == false){
				//KT - STRY0050725: if this is a subtask get the list of primary assignee outas and check that the current user is in the list
				listOfPrimaryAssigneeOUTAs  =  current.parent.parent.primary_assignee.tasking_authorities;
				arrayPrimaryAssigneeOUTAs = listOfPrimaryAssigneeOUTAs.toString().split(",");
				isPrimaryAssigneeOUTA = arrayUtil.contains(arrayPrimaryAssigneeOUTAs, currentUser); 
			}
		}

		// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Manager of Task owner
		var isTaskManagerOfTaskOwner = new UserInfoScripts().IsUserOUTAOfAnotherUser(taskOwner, currentUser);

		//KT: gr is from Task table: uses gr directly
		if (canRead && clarificationRequested == true) {

			//if clarification requested is true and any of the above states is true
			if((unassigned || assigned || accepted || workInProgress || inReview  || reWork)){
				//Top Task //05.27.20: Condition fixed 
				if(isTopTask == true){ 
					// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Administrators to the people who can respond
					if(taskOwner || isPrimaryOfficeOUTA  || isTaskAdministrator || isTaskManagerOfTaskOwner){ 
						return true;
					}else{
						return false;
					}
				}
				//Sub Task //05.27.20: Condition fixed 
				if(isTopTask == false){
					// STRY0101692 - REQ – Respond Clarification Request via Modal  - add Task Administrators to the people who can respond
					if(taskOwner || isPrimaryAssigneeOUTA || isTaskAdministrator || isTaskManagerOfTaskOwner){
						return true;
					}else{
						return false;
					}
				}
			}
		}
		else return false;
	},


