	// STRY0065020 user can run a template
	// This controls running a template from the Template area as a new task tree
	// This function expects to receive the Template record
	runTemplateUIAction: function(gr)
	{
		var canRead = gr.canRead();
		var newRecord = gr.sys_id;
		var isActive;

		// STRY0074534 Template Admins can read any template
		var grTemplate;
		var grTemp;
		if (gr.getTableName() == "x_153465_discovert_discover_routing_template") {
			isActive = gr.u_active;
			grTemplate = gr;
		} else if (gr.getTableName() == "x_153465_discovert_route_tasks") {
			isActive = gr.active;
			grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
			if(grTemp.get(gr.tasker_process_definition)){
				grTemplate = grTemp;
			} else return false;
		// STRY0075793 - TUP-Run Template from Task in the Platform Pages
		} else if (gr.getTableName() == "x_153465_discovert_discover_routing_runtime") {
			// STRY0079327 - fixed... this had the Template Instance  table name instead of the Template table name
			grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
			if(grTemp.get(gr.routing_template_ref)){
				isActive = gr.u_active;
				grTemplate = grTemp;
			} else return false;
		} else {
			return false;
		} 

		var isProcessOwner = grTemplate.getValue('process_owner') == gs.getUserID();
		var processLevel = grTemplate.getValue('process_level');
		var UserPermissions  = new UserInfoScripts();
		// STRY0085827
		if(canRead && (newRecord != -1) && isActive == true ){
			if (processLevel == 'global_process') 
				return UserPermissions.IsUserTaskAdministrator(gs.getUserID());
			else if (processLevel == 'ou_process')
				return UserPermissions.isGivenUserOUTA(gs.getUserID(), grTemplate.getValue('process_ou'));
			else if (processLevel == 'my_process')
				return grTemplate.getValue('process_owner') == gs.getUserID();
			else
				return false;
		} else return false;
	},

