	//STRY0017099 KB 2019-05-08 Updated to add TaskOwner and other checks
	IsUserTaskingAuthorityOrReviewer: function(taskRecord) {
		if(taskRecord.isNewRecord()) {
			return true;
		}
		try{
			var user = gs.getUserID();
			var uis = new UserInfoScripts();
			var taskOwner = taskRecord.u_task_requester;
			var taskOwnerAllowed = (taskOwner == user);
			var isTaskOwnerOUTA = uis.IsUserOUTAOfAnotherUser(taskOwner, user);
			var globalTAAllowed = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
			var onBehalfOfAllowed = ((taskRecord.parent && taskRecord.parent.on_behalf_of == user) || (!taskRecord.parent && taskRecord.on_behalf_of == user));

			if(globalTAAllowed || isTaskOwnerOUTA || taskOwnerAllowed || onBehalfOfAllowed ) {
				return true;
			}
		}catch(e) {
			gs.error(e);
		}

		return false;
	},
	//STRY0031122 KB 2019-05-08 Added to provide support for Risk Flag ACL
	IsAssigneeTaskOwnerOrTA: function(taskRecord) {
		if(taskRecord.isNewRecord()) {
			return true;
		}
		try{
			var user = gs.getUserID();
			var ous = new OrganizationalScripts();
			var taskOwner = taskRecord.u_task_requester;
			var taskOwnerAllowed = (taskOwner == user);
			var assignee = taskRecord.assigned_to;
			var assigneeAllowed = (assignee == user);
			var assigneeOU = ous.GetUserDefaultOU(assignee);
			var isAssigneeOUTA = new UserInfoScripts().IsUserTaskingAuthority(assigneeOU, user);
			var globalTAAllowed = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

			if(globalTAAllowed || isAssigneeOUTA || taskOwnerAllowed || assigneeAllowed ) {
				return true;
			}
		}catch(e) {
			gs.error(e);
		}

		return false;
	},
