		}
	},

	UserCanReopenCompletedTask: function(task) {
		var isNewRecord = task.isNewRecord();
		var canRead = task.canRead();
		var isActive = task.active;

		var user = gs.getUser();
		var userId = user.getID();
		var isTaskOwner = (task.u_task_requester == userId);
		var isReviewer = (task.u_reviewer == userId);
		var isAssignedMember = (task.assigned_to == userId);

		var isOnBehalfOf = (task.on_behalf_of && task.on_behalf_of == userId);
		var isTaskAdministrator = user.hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

		var userCanReOpen = (isTaskOwner || isOnBehalfOf || isReviewer || isAssignedMember || isTaskAdministrator);
		var answer = canRead && !isNewRecord && !isActive && userCanReOpen;

		return answer;
	},
	// gets the user from the saved user preferences, a temporary variable containing the current ou
	getOuFromSessionIfNotPresent: function(ouId) {
		var ou = ouId;
		if(ouId) {
			return ouId;
		}
		try {
			// grab and clear the value of the current ou from the user's preferences
			ou = gs.getUser().getPreference("CurrentOU");
			gs.getUser().savePreference("CurrentOU", "");
		} catch (e) {
			gs.warn(e);
		}
		return ou;
	},

	// get the user from the uri if not present on the record
	getOuFromUriIfNotPresent: function(ouId) {
		var ou = ouId;
		if(ouId) {
			return ouId;
		}
		try{
			var uri = gs.action.getGlideURI().get("query");
			if(uri) {
				var eqIdex = uri.indexOf("=");
				ou = uri.substring(eqIdex+1);
			}
		}catch(e){
			ou = ouId;
		}

		return ou;
	},

	saveTaskAsProcessTemplate: function(gr){
		// use the standard UserInfo scripts to check user permissions
		var UserPermissions  = new UserInfoScripts();
		var tasker_process_template_global = UserPermissions.userHasGlobalProcessRights();
		// v2.5.13 - STRY0073150 - the template is saved as a Personal Template.
		// The user does not need OU Template rights to do that.
		//var task_process_template_ou = UserPermissions.userHasOUProcessRightsOnAnOU();
		var tasker_process_template_user = UserPermissions.userHasPersonalProcessRights();
		var task_process_template_admin = UserPermissions.userHasProcessTemplateAdminRights();

		var isNewRecord = gr.isNewRecord();
		var arrayUtil = new global.ArrayUtil();
		var canRead = current.canRead();
		var currentUser =  gs.getUserID();
		var clarificationRequested;
		var isTopTask;
		//if task is in any of the below states
		var unassigned = (current.state == "-5");
		var assigned  = (current.state == "1");
		var accepted = (current.state == "10");
		var workInProgress = (current.state == "13");
		var inReview = (current.state == "14");
		var reWork = (current.state == "15");
		//check the to see if the current logged in user has any of the following tasker roles
		var userIsTaskAdministrator = UserPermissions.IsUserTaskAdministrator(gs.getUserID());
		var taskOwner = (current.u_task_requester == currentUser);
		var currentUserIsAssignedMember = (current.assigned_to == currentUser);
		var currentUserIsReviewer = (current.u_reviewer == currentUser);
		var arrayTaskingAuthorityOUTAs = [];
		var listOfTaskingAuthorityOUTAs;
		var isTaskingAuthorityOUTA;
		var arrayPrimaryOfficeOUTAs = [];
		var listOfPrimaryOfficeOUTAs;
		var isPrimaryOfficeOUTA;
		var arrayPrimaryAssigneeOUTAs = [];
		var listOfPrimaryAssigneeOUTAs;
		var isPrimaryAssigneeOUTA;

		if(current.tasking_authority + '' != ''){
			listOfTaskingAuthorityOUTAs = current.tasking_authority.tasking_authorities;
			arrayTaskingAuthorityOUTAs = listOfTaskingAuthorityOUTAs.toString().split(",");
			isTaskingAuthorityOUTA = arrayUtil.contains(arrayTaskingAuthorityOUTAs, currentUser);
		}

		if(current.primary_office + '' != ''){
			listOfPrimaryOfficeOUTAs = current.primary_office.tasking_authorities;
			arrayPrimaryOfficeOUTAs = listOfPrimaryOfficeOUTAs.toString().split(",");
			isPrimaryOfficeOUTA = arrayUtil.contains(arrayPrimaryOfficeOUTAs, currentUser);
		}
		if(current.primary_assignee + '' != ''){
			listOfPrimaryAssigneeOUTAs = current.primary_assignee.tasking_authorities;
			arrayPrimaryAssigneeOUTAs = listOfPrimaryAssigneeOUTAs.toString().split(",");
			isPrimaryAssigneeOUTA = arrayUtil.contains(arrayPrimaryAssigneeOUTAs, currentUser); 
		}
		// v2.5.13 - STRY0073150 - removed task_process_template_ou 
		// The template is saved as a Personal Template, the user does not need OU Template rights to do that.
		if(canRead && !isNewRecord &&(task_process_template_admin || tasker_process_template_global || tasker_process_template_user)){
			if(userIsTaskAdministrator || taskOwner || isTaskingAuthorityOUTA || isPrimaryOfficeOUTA || isPrimaryAssigneeOUTA){
				return true;
			} else if(currentUserIsAssignedMember && !unassigned && !assigned){
				return true;
			} else if (currentUserIsReviewer && !unassigned && !assigned && !accepted && !workInProgress && !reWork){
				return true;
			} else return false;
		}
		else return false;
	},

	/* START  OF PROCESS ENABLE/DISABLE DOC SHARING */	
	// RAJ 2020.03.18  STRY0063547
	processEnableSharedAttachments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,false,'attachment');		
	},

	// RAJ 2020.03.18  STRY0063547
	processDisableSharedAttachments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,true,'attachment');
	},

	// RAJ 2020.03.18  STRY0063747
	processEnableSharedDocuments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,false,'document');
	},

	// RAJ 2020.03.18  STRY0063747
	processDisableSharedDocuments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,true,'document');
	},
	/* END OF PROCESS ENABLE/DISABLE DOC SHARING */	

	// RAJ 2020.03.18  STRY0063747
	// All of the states for documents being enabled or disabled are contained in this function
	// checkSharedEnabled will be what the calling function is asking
	// When called from an "Enable" UI action, false should be passed b/c that ui action if on if sharing is currently disabled.
	// When calling from a "disable" UI action, true should be passed b/c that ui action is on if sharing is currently enabled
	validAttachmentOrDocumentRecord: function(gr, checkSharedEnabled, docsOrAttachmentCheck){
		var canRead = gr.canRead();
		var isActive = gr.active;
		var isNewRecord = gr.isNewRecord();
		var recordTable = gr.getTableName();
		var isNotShared;
		var userInfo = new UserInfoScripts();
		var tDS = new taskerDocumentScripts();

		var userHasPermissions = false;
		var correctRecordLevel = false;
		var currentUserID = gs.getUserID();
		if (recordTable == 'x_153465_discovert_route_task_instance'){
			// is the current user the task owner?
			var taskOwner = gr.u_task_requester == currentUserID;
			// enable/disable are only on the top task
			correctRecordLevel =  gr.parent.nil();  
			// STRY0073605 - top task Assigneed Member can also enable and disable Shared docuements and shared attachments
			var assignedTo = gr.assigned_to == currentUserID;
			// who can enable, only OUTA of the Primary Office or the Task Owner
			userHasPermissions = taskOwner || assignedTo;  
		} else if (recordTable == 'x_153465_discovert_discover_routing_template'){
			// this is the process template.  So, the table is the correct level
			correctRecordLevel = true;
			userHasPermissions = userInfo.userHasProcessRights(gr);
		} else if(recordTable == 'x_153465_discovert_route_tasks'){
			// enable/disable are only on the top Process Template Task
			correctRecordLevel =  gr.parent.nil();  
			userHasPermissions = userInfo.userHasProcessRights(gr);
		}
		var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(gr);

		var isShareinRightState = false;
		if(docsOrAttachmentCheck == 'attachment'){
			isShareinRightState = (checkSharedEnabled==currentAttachDocSettings.sharingAttachments && currentAttachDocSettings.sNOWAttachmentsOn);
		} else if (docsOrAttachmentCheck == 'document'){
			isShareinRightState = (checkSharedEnabled==currentAttachDocSettings.sharingDocuments && currentAttachDocSettings.docIntDocumentsOn);
		}
		if(canRead && !isNewRecord && correctRecordLevel && isShareinRightState && userHasPermissions){
			return true;
		}else{
			return false;
		}

	},

	// RAJ 2020.02.17  STRY0060676
	enableSharedAttachments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,false,'attachment');
	},

	// RAJ 2020.02.17  STRY0060676
	disableSharedAttachments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,true, 'attachment');
	},

	// RAJ 2020.02.22  STRY0059166
	enableSharedDocuments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,false,'document');
	},

	// RAJ 2020.02.22  STRY0059166
	disableSharedDocuments: function(gr){
		return this.validAttachmentOrDocumentRecord(gr,true,'document');
	},

	//check if member has organizational admin or is in ou (for acl)
	MemberHasOrgAdminOrInOU: function(ouMember) {
		try {
			var currentUser = gs.getUser();
			var userId = currentUser.getID();
			// first check if the hierarchy is on record (does not work for new records [its blank])
			var ouId = ouMember.discover_office_hierarchy;
			// workaround if we still dont have a current ou
			ouId = this.getOuFromUriIfNotPresent(ouId);
			// workaround for new records if the hierarchy doesn't contain value and if uri is not available
			ouId = this.getOuFromSessionIfNotPresent(ouId);
			var result = false;
			if(ouId) {
				gs.getUser().savePreference("CurrentOU", ouId.toString());
				var uis = new UserInfoScripts();
				var userIsInOu = uis.IsUserInOU(ouId, userId);
				var userHasGlobalRole = currentUser.hasRole("x_153465_discovert.tasker_organizational_admin");


				if(userHasGlobalRole || userIsInOu) {
					result = true;
				}
			}
			return result;
		} catch(e) {
			gs.warn("[New OU Member ACL] exception occurred: " + e);
			return false;
		}


	},


	displaySendTaskAsEmailUIAction: function(current){

		//HT -STRY0058721
		//get the disableExportTaskFunction system property, it defaults to false
		// STRY0101754 - this returns a string, was not working for all cases.  
		// Change to boolean and update the other if statements below to use boolean instead of string
		var isTaskAsEmailFunctionDisabled = gs.getProperty("x_153465_discovert.#DisableExportTaskToEmailFunction") == "true";	
		var canRead = (current.canRead() == true);
		//if the above system property is set to false the export functionality is NOT disabled
		// STRY0101754
		if(canRead && !isTaskAsEmailFunctionDisabled){
			//check to see if the current task is in a restricted group
			//if the task is in a restricted group do not should the export task as email UI Action
			if(current.assignment_group.nil() && current.assignment_group == ""){
				return true;
			}else{
				return false;
			}
		}
		// STRY0101754
		if(isTaskAsEmailFunctionDisabled){
			return false;
		}	
	},

	type: 'uiConditionCheck'
};
